import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle

class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        val intent = intent
        if (intent != null && intent.data != null) {
            handleDeepLink(intent.data.toString())
        }
    }

    private fun handleDeepLink(url: String) {
        when {
            url.startsWith("myapp://profile/") -> {
                val id = url.substringAfterLast("/")
                startActivity(Intent(this, ProfileActivity::class.java).apply {
                    putExtra(ProfileActivity.EXTRA_ID, id)
                })
            }
            url.startsWith("myapp://payment/confirm") -> {
                startActivity(Intent(this, PaymentConfirmActivity::class.java))
            }
        }
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        if (intent != null && intent.data != null) {
            handleDeepLink(intent.data.toString())
        }
    }
}

fun AppCompatActivity.handleDeepLink(url: String) {
    val uri = Uri.parse(url)
    when {
        uri.scheme == "myapp" -> {
            when {
                uri.path.startsWith("/profile/") -> {
                    val id = uri.path.substringAfterLast("/")
                    startActivity(Intent(this, ProfileActivity::class.java).apply {
                        putExtra(ProfileActivity.EXTRA_ID, id)
                    })
                }
                uri.path.startsWith("/payment/confirm") -> {
                    startActivity(Intent(this, PaymentConfirmActivity::class.java))
                }
            }
        }
    }
}